/**
 * PressVideo — Music mode / persistent mini-player.
 * Vanilla JS. No jQuery, no Bootstrap.
 *
 * Listens for pv:minimize-requested, manages the 72px bottom bar,
 * and keeps the YouTube iframe alive in the DOM so audio continues.
 */
(function () {
    'use strict';

    var CANVAS_ID = 'pv-canvas';

    var canvas, miniBar, miniPlay, miniTitle, miniArtist, miniThumb,
        miniPrev, miniNext, miniExpand, miniClose, miniProgressWrap, miniProgressFill;

    var minimized   = false;
    var currentSlide = null;

    function init() {
        canvas = document.getElementById(CANVAS_ID);
        if (!canvas) return;

        miniBar          = canvas.querySelector('.pv-mini-bar');
        miniPlay         = canvas.querySelector('.pv-mini-play');
        miniTitle        = canvas.querySelector('.pv-mini-bar__title');
        miniArtist       = canvas.querySelector('.pv-mini-bar__artist');
        miniThumb        = canvas.querySelector('.pv-mini-bar__thumb');
        miniPrev         = canvas.querySelector('.pv-mini-prev');
        miniNext         = canvas.querySelector('.pv-mini-next');
        miniExpand       = canvas.querySelector('.pv-mini-expand');
        miniClose        = canvas.querySelector('.pv-mini-close');
        miniProgressWrap = canvas.querySelector('.pv-mini-bar__progress');
        miniProgressFill = canvas.querySelector('.pv-mini-bar__progress-fill');

        // Triggered by offcanvas.js close() intercept for music content
        canvas.addEventListener('pv:minimize-requested', onMinimizeRequested);

        // Progress tick from lazy-video.js
        canvas.addEventListener('pv:progress-updated', onProgressUpdated);

        // Player state (playing/paused) from lazy-video.js
        canvas.addEventListener('pv:player-state-changed', onPlayerStateChanged);

        // Slide changed — update mini-bar info even while minimized
        canvas.addEventListener('pv:slide-changed', onSlideChanged);

        // Fully closed from elsewhere — reset minimized state
        canvas.addEventListener('pv:closed', onClosed);

        if (miniPlay)   miniPlay.addEventListener('click', onPlayPauseClick);
        if (miniPrev)   miniPrev.addEventListener('click', function () { onNavClick(-1); });
        if (miniNext)   miniNext.addEventListener('click', function () { onNavClick(1); });
        if (miniExpand) miniExpand.addEventListener('click', restore);
        if (miniClose)  miniClose.addEventListener('click', forceClose);

        if (miniProgressWrap) {
            miniProgressWrap.addEventListener('click', function (e) {
                var rect = miniProgressWrap.getBoundingClientRect();
                var pct  = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
                canvas.dispatchEvent(new CustomEvent('pv:seek-pct', { bubbles: false, detail: { pct: pct } }));
            });
        }
    }

    /* ── Minimize: panel → 72px bar ─────────────────────────────── */
    function onMinimizeRequested(e) {
        currentSlide = (e.detail && e.detail.slide) || null;
        minimize();
    }

    function minimize() {
        minimized = true;
        canvas.classList.add('pv-offcanvas--minimized');
        document.body.style.overflow = '';
        updateMiniBar();
    }

    /* ── Restore: bar → full panel ───────────────────────────────── */
    function restore() {
        if (!minimized) return;
        minimized = false;
        canvas.classList.remove('pv-offcanvas--minimized');
        document.body.style.overflow = 'hidden';
    }

    /* ── Force close (stop audio, destroy player) ────────────────── */
    function forceClose() {
        minimized    = false;
        currentSlide = null;
        if (canvas.pvForceClose) canvas.pvForceClose();
    }

    /* ── Slide changed ───────────────────────────────────────────── */
    function onSlideChanged(e) {
        currentSlide = (e.detail && e.detail.slide) || currentSlide;
        if (minimized) updateMiniBar();
    }

    /* ── Mini-bar content ────────────────────────────────────────── */
    function updateMiniBar() {
        if (!currentSlide) return;
        if (miniTitle)  miniTitle.textContent  = currentSlide.title  || '';
        if (miniArtist) miniArtist.textContent = currentSlide.artist || '';
        if (miniThumb)  {
            miniThumb.src = currentSlide.thumb || '';
            miniThumb.alt = currentSlide.title || '';
        }
        if (miniProgressFill) miniProgressFill.style.width = '0%';
    }

    /* ── Progress bar ────────────────────────────────────────────── */
    function onProgressUpdated(e) {
        if (!minimized || !miniProgressFill) return;
        var d = e.detail || {};
        if (d.pct >= 0) miniProgressFill.style.width = Math.min(d.pct * 100, 100).toFixed(1) + '%';
    }

    /* ── Play/pause button ───────────────────────────────────────── */
    function onPlayPauseClick() {
        if (!miniBar) return;
        var playing = miniBar.classList.contains('pv-mini-bar--playing');
        if (playing) {
            canvas.dispatchEvent(new CustomEvent('pv:pause-player', { bubbles: false }));
            miniBar.classList.remove('pv-mini-bar--playing');
        } else {
            canvas.dispatchEvent(new CustomEvent('pv:resume-player', { bubbles: false }));
            miniBar.classList.add('pv-mini-bar--playing');
        }
    }

    /* ── Player state sync ───────────────────────────────────────── */
    function onPlayerStateChanged(e) {
        if (!miniBar) return;
        var state = e.detail && e.detail.state;
        // YT.PlayerState.PLAYING = 1, PAUSED = 2, ENDED = 0, BUFFERING = 3
        if (state === 1) {
            miniBar.classList.add('pv-mini-bar--playing');
        } else if (state === 2 || state === 0) {
            miniBar.classList.remove('pv-mini-bar--playing');
        }
    }

    /* ── Nav from mini-bar ───────────────────────────────────────── */
    function onNavClick(delta) {
        // Restore full panel first so new song loads visibly
        restore();
        if (canvas.pvNavigate) canvas.pvNavigate(delta);
    }

    /* ── Reset on full close ─────────────────────────────────────── */
    function onClosed() {
        minimized    = false;
        currentSlide = null;
        if (miniBar) {
            miniBar.classList.remove('pv-mini-bar--playing');
            if (miniProgressFill) miniProgressFill.style.width = '0%';
        }
    }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
    else init();
}());
